function fixNetworkPorts(includedPorts, excludedPorts) {
    let output = new Set(includedPorts);
    excludedPorts.forEach(port => output.delete(port));
    return Array.from(output);
}

solutions.python:
class Solution:
    def fix_network_ports(self, included_ports, excluded_ports) -> []:
        output = set(included_ports)
        for port in excluded_ports:
            output.discard(port)
        return list(output)
